"""
Intelligent Routing System for OpenCode LLM Orchestration
Reference: blueprint.txt "Routing (Detectors → Lanes → Budgets)"
Implementation of advanced LLM orchestration concepts
"""

import re
import asyncio
import logging
from dataclasses import dataclass, field
from typing import Dict, List, Optional, Tuple, Any
from enum import Enum
from .config import Config
from .context_scorer import AdaptiveContextScorer

from .config import Config

logger = logging.getLogger(__name__)

class IntentType(Enum):
    """Intent classification types"""
    STRUCTURED = "structured"
    CONTINUATION = "continuation"
    REASONING = "reasoning"
    RECALL = "recall"
    TOOL_USE = "tool_use"
    GENERAL = "general"

class Lane(Enum):
    """Processing lanes with different optimization profiles"""
    STANDARD = "standard"
    DELIBERATE = "deliberate"
    RECALL = "recall"
    TOOL_USE = "tool_use"

@dataclass
class IntentResult:
    """Result of intent detection"""
    intent_type: IntentType
    confidence: float
    metadata: Dict[str, Any] = field(default_factory=dict)

@dataclass
class RouteResult:
    """Result of routing decision"""
    lane: Lane
    intent_type: IntentType
    confidence: float
    config_overrides: Dict[str, Any] = field(default_factory=dict)
    metadata: Dict[str, Any] = field(default_factory=dict)
    estimated_tokens: int = 0
    estimated_time: float = 0.0

    def __post_init__(self):
        # Clamp confidence to [0.0, 1.0]
        try:
            self.confidence = max(0.0, min(1.0, float(self.confidence)))
        except Exception:
            self.confidence = 0.5
        # Ensure dict types
        if not isinstance(self.metadata, dict):
            self.metadata = {}
        if not isinstance(self.config_overrides, dict):
            self.config_overrides = {}

class IntentDetector:
    """
    Implements intent detection logic from blueprint.txt lines 14-29
    Reference: "Structured-Intent Detector", "Continuation/Recall Detector", etc.
    """

    def __init__(self):
        self.structured_patterns = [
            # List requests: "list N items", "give me X examples", "list N things"
            r'(?:list|give\s+me|show\s+me|provide)\s+(\d+)\s+(?:items?|examples?|things?|options?|ways?)',
            # Simple "List N" patterns
            r'list\s+(\d+)\s+\w+',
            # "N things/items" patterns
            r'(\d+)\s+(?:items?|examples?|things?|types?|kinds?|species?)',
            # JSON/structured format requests
            r'(?:json|JSON)\s+(?:format|structure|schema)',
            r'(?:format.*json|structure.*json)',
            # Table/tabular requests
            r'(?:table|tabular|spreadsheet|csv|columns?)',
            # Schema/field requests
            r'(?:schema|fields?|properties|attributes)',
            # Numbered list indicators
            r'(?:numbered\s+list|bullet\s+points?|step\s+by\s+step\s+list)',
        ]

        self.continuation_patterns = [
            # Direct continuation requests
            r'(?:^|\s)(?:continue|carry\s+on|keep\s+going|more)(?:\s|$)',
            # "Again" style requests
            r'(?:again|repeat|same\s+(?:thing|style|format))',
            # "Add more" requests
            r'(?:add\s+(?:more|\d+\s+more)|give\s+me\s+more)',
            # Quantity recalls
            r'(?:how\s+many|what\s+was\s+the\s+(?:count|number))',
        ]

        self.reasoning_patterns = [
            # Explanation requests
            r'(?:explain\s+(?:why|how)|what\s+(?:causes?|makes?))',
            # Analysis requests
            r'(?:analyze|analysis|break\s+down|root\s+cause)',
            # Step-by-step requests
            r'(?:step\s+by\s+step|walkthrough|process)',
            # Reasoning keywords
            r'(?:because|reasoning|rationale|logic)',
        ]

        self.recall_patterns = [
            # Memory queries
            r'(?:what\s+(?:did\s+)?(?:we|I)\s+(?:discuss|talk\s+about|cover))',
            r'(?:remind\s+me|recall|remember)',
            # Previous reference
            r'(?:(?:the\s+)?(?:last|previous|earlier)\s+(?:time|conversation|discussion))',
            # "How many" about previous items
            r'(?:how\s+many.*(?:listed|mentioned|discussed))',
        ]

        self.tool_patterns = [
            # File operations
            r'(?:read|open|show|display|list).*(?:file|document|directory|folder)',
            r'(?:write|create|save|edit).*(?:file|document)',
            # Directory operations
            r'(?:list|show).*(?:files|directories|contents)',
            r'current\s+directory',
            # Search operations
            r'(?:search|find|grep|look\s+for)',
            # System operations
            r'(?:run|execute|command|bash|shell)',
            # Git operations
            r'(?:git\s+|version\s+control|commit|push|pull)',
        ]

    def detect_structured_intent(self, user_input: str) -> IntentResult:
        """
        Detect structured output requests (lists, JSON, tables, etc.)
        Reference: blueprint.txt "n_items / format / table / schema_fields"
        """
        confidence = 0.0
        metadata = {}

        text_lower = user_input.lower()

        # Check each pattern type
        for pattern in self.structured_patterns:
            match = re.search(pattern, text_lower)
            if match:
                confidence = max(confidence, 0.8)

                # Extract number if present
                if match.groups():
                    try:
                        metadata['requested_count'] = int(match.group(1))
                    except (ValueError, IndexError):
                        pass

                # Identify specific format type
                if any(word in text_lower for word in ['json', 'format', 'structure']):
                    metadata['format_type'] = 'json'
                    confidence = max(confidence, 0.9)
                elif any(word in text_lower for word in ['table', 'tabular', 'csv']):
                    metadata['format_type'] = 'table'
                    confidence = max(confidence, 0.85)
                elif any(word in text_lower for word in ['list', 'items', 'examples']):
                    metadata['format_type'] = 'list'
                    confidence = max(confidence, 0.8)

        return IntentResult(
            intent_type=IntentType.STRUCTURED,
            confidence=confidence,
            metadata=metadata
        )

    def detect_continuation(self, user_input: str) -> IntentResult:
        """
        Detect continuation requests
        Reference: blueprint.txt "continue", "carry on", "more", "again same"
        """
        confidence = 0.0
        metadata = {}

        text_lower = user_input.lower().strip()

        # High confidence for direct continuation words
        if text_lower in ['continue', 'more', 'again', 'carry on']:
            confidence = 0.95
            metadata['continuation_type'] = 'direct'

        # Pattern-based detection
        for pattern in self.continuation_patterns:
            if re.search(pattern, text_lower):
                confidence = max(confidence, 0.8)

                if 'more' in text_lower:
                    metadata['continuation_type'] = 'add_more'
                elif 'again' in text_lower or 'same' in text_lower:
                    metadata['continuation_type'] = 'repeat'
                elif 'how many' in text_lower:
                    metadata['continuation_type'] = 'count_query'
                    confidence = max(confidence, 0.9)

        return IntentResult(
            intent_type=IntentType.CONTINUATION,
            confidence=confidence,
            metadata=metadata
        )

    def detect_reasoning_need(self, user_input: str) -> IntentResult:
        """
        Detect reasoning/explanation requests
        Reference: blueprint.txt "explain why", "root cause", "step by step"
        """
        confidence = 0.0
        metadata = {}

        text_lower = user_input.lower()

        # Strong reasoning indicators
        strong_indicators = ['explain why', 'root cause', 'step by step', 'walk me through']
        for indicator in strong_indicators:
            if indicator in text_lower:
                confidence = 0.9
                metadata['reasoning_type'] = 'explanation'
                break

        # Pattern-based detection
        for pattern in self.reasoning_patterns:
            if re.search(pattern, text_lower):
                confidence = max(confidence, 0.7)

                if any(word in text_lower for word in ['explain', 'why', 'how']):
                    metadata['reasoning_type'] = 'explanation'
                elif any(word in text_lower for word in ['analyze', 'analysis']):
                    metadata['reasoning_type'] = 'analysis'
                elif 'step' in text_lower:
                    metadata['reasoning_type'] = 'process'

        return IntentResult(
            intent_type=IntentType.REASONING,
            confidence=confidence,
            metadata=metadata
        )

    def detect_recall_intent(self, user_input: str) -> IntentResult:
        """
        Detect memory/recall requests
        Reference: blueprint.txt "how many" queries about previous content
        """
        confidence = 0.0
        metadata = {}

        text_lower = user_input.lower()

        # High confidence recall patterns
        if any(phrase in text_lower for phrase in ['how many', 'what did we', 'remind me']):
            confidence = 0.9
            metadata['recall_type'] = 'memory_query'

        # Pattern-based detection
        for pattern in self.recall_patterns:
            if re.search(pattern, text_lower):
                confidence = max(confidence, 0.8)

                if 'how many' in text_lower:
                    metadata['recall_type'] = 'count_recall'
                elif any(word in text_lower for word in ['remind', 'recall', 'remember']):
                    metadata['recall_type'] = 'memory_query'
                elif any(word in text_lower for word in ['last', 'previous', 'earlier']):
                    metadata['recall_type'] = 'previous_reference'

        return IntentResult(
            intent_type=IntentType.RECALL,
            confidence=confidence,
            metadata=metadata
        )

    def detect_tool_requirements(self, user_input: str) -> IntentResult:
        """
        Detect tool usage requirements
        """
        confidence = 0.0
        metadata = {}

        text_lower = user_input.lower()

        # Tool requirement patterns
        for pattern in self.tool_patterns:
            if re.search(pattern, text_lower):
                confidence = max(confidence, 0.8)

                if any(word in text_lower for word in ['file', 'read', 'write', 'open']):
                    metadata['tool_type'] = 'file_operations'
                elif any(word in text_lower for word in ['search', 'find', 'grep']):
                    metadata['tool_type'] = 'search_operations'
                elif any(word in text_lower for word in ['run', 'execute', 'command']):
                    metadata['tool_type'] = 'system_operations'
                elif 'git' in text_lower:
                    metadata['tool_type'] = 'git_operations'

        return IntentResult(
            intent_type=IntentType.TOOL_USE,
            confidence=confidence,
            metadata=metadata
        )

class LaneManager:
    """
    Implements lane configurations and budgets from blueprint.txt lines 32-36
    Reference: "standard/deliberate/recall" lane specifications
    """

    # Lane configurations from blueprint.txt
    LANE_CONFIGS = {
        Lane.STANDARD: {
            'max_tokens': 500,
            'timeout': 12,
            'retries': [1.0],
            'temperature_modifier': 0.0,
            'description': 'Standard responses with JSON-first approach'
        },
        Lane.DELIBERATE: {
            'max_tokens': 800,
            'timeout': 25,
            'retries': [1.0, 0.7],
            'temperature_modifier': 0.1,
            'description': 'Reasoning and analysis with extended time'
        },
        Lane.RECALL: {
            'max_tokens': 64,
            'timeout': 5,
            'retries': [1.0],
            'temperature_modifier': -0.2,
            'description': 'Memory queries with minimal LLM usage'
        },
        Lane.TOOL_USE: {
            'max_tokens': 600,
            'timeout': 15,
            'retries': [1.0],
            'temperature_modifier': -0.1,
            'description': 'Tool coordination and execution'
        }
    }

    def get_lane_config(self, lane: Lane) -> Dict[str, Any]:
        """Get configuration for specified lane"""
        return self.LANE_CONFIGS.get(lane, self.LANE_CONFIGS[Lane.STANDARD]).copy()

    def estimate_resource_usage(self, lane: Lane, input_complexity: float = 1.0) -> Tuple[int, float]:
        """
        Estimate token usage and time for lane
        Returns: (estimated_tokens, estimated_time)
        """
        config = self.get_lane_config(lane)

        # Base estimates
        base_tokens = config['max_tokens']
        base_time = config['timeout'] * 0.8  # Assume 80% of timeout typically used

        # Adjust for input complexity
        estimated_tokens = int(base_tokens * input_complexity)
        estimated_time = base_time * input_complexity

        return estimated_tokens, estimated_time

class OpenCodeRouter:
    """
    Main routing orchestrator implementing blueprint.txt routing logic
    Reference: "Router Decision" flow from blueprint.txt lines 25-29
    """

    def __init__(self, config: Config):
        self.config = config
        self.intent_detector = IntentDetector()
        self.lane_manager = LaneManager()
        # Context scorer for recall gating
        try:
            self.scorer = AdaptiveContextScorer(config)
        except Exception:
            self.scorer = None

        # Routing thresholds from config
        self.structured_threshold = config.routing.structured_threshold
        self.continuation_threshold = config.routing.continuation_threshold
        self.reasoning_threshold = config.routing.reasoning_threshold
        self.recall_threshold = config.routing.recall_threshold
        self.tool_threshold = config.routing.tool_threshold

    async def route_request(self, user_input: str, context: Dict[str, Any]) -> RouteResult:
        """
        Main routing logic implementing blueprint.txt decision tree
        Reference: blueprint.txt "Router Decision" section
        """
        # Run all intent detections
        intent_results = {
            'structured': self.intent_detector.detect_structured_intent(user_input),
            'continuation': self.intent_detector.detect_continuation(user_input),
            'reasoning': self.intent_detector.detect_reasoning_need(user_input),
            'recall': self.intent_detector.detect_recall_intent(user_input),
            'tool_use': self.intent_detector.detect_tool_requirements(user_input)
        }

        # Log detection results
        logger.info(f"Intent detection results: {[(k, v.confidence) for k, v in intent_results.items()]}")

        # Apply routing logic from blueprint.txt
        # Priority order: Structured -> Continuation/Recall -> Reasoning -> Tool Use -> Standard

        if intent_results['structured'].confidence >= self.structured_threshold:
            return self._route_to_structured(intent_results['structured'], context)

        elif (intent_results['continuation'].confidence >= self.continuation_threshold or
              intent_results['recall'].confidence >= self.recall_threshold):
            # Prefer recall only if memory gate passes; otherwise continuation
            recall_ok = self._should_route_recall(user_input, context) if intent_results['recall'].confidence >= self.recall_threshold else False
            if recall_ok:
                return self._route_to_recall(intent_results['recall'], context)
            if intent_results['continuation'].confidence >= self.continuation_threshold:
                return self._route_to_continuation(intent_results['continuation'], context)
            # Fall through to standard if neither is clearly valid
            return self._route_to_standard(user_input, context)

        elif intent_results['reasoning'].confidence >= self.reasoning_threshold:
            return self._route_to_deliberate(intent_results['reasoning'], context)

        elif intent_results['tool_use'].confidence >= self.tool_threshold:
            return self._route_to_tool_use(intent_results['tool_use'], context)

        else:
            # Default to standard lane
            return self._route_to_standard(user_input, context)

    def _route_to_continuation(self, intent_result: IntentResult, context: Dict) -> RouteResult:
        """Route continuation requests to STANDARD lane with continuation metadata.

        This avoids false recall routing while signaling downstream that the
        user likely wants more of the previous format/content.
        """
        config = self.lane_manager.get_lane_config(Lane.STANDARD)

        config_overrides = {
            'continuation': True,
            'structured_mode': False,
        }

        estimated_tokens, estimated_time = self.lane_manager.estimate_resource_usage(
            Lane.STANDARD, input_complexity=1.0
        )

        return RouteResult(
            lane=Lane.STANDARD,
            intent_type=IntentType.CONTINUATION,
            confidence=intent_result.confidence,
            config_overrides=config_overrides,
            metadata={
                'routing_reason': 'continuation_intent_detected',
                'intent_metadata': intent_result.metadata,
                **config
            },
            estimated_tokens=estimated_tokens,
            estimated_time=estimated_time
        )

    def _route_to_structured(self, intent_result: IntentResult, context: Dict) -> RouteResult:
        """Route to standard lane with structured output optimization"""
        config = self.lane_manager.get_lane_config(Lane.STANDARD)

        # Structured optimization: lower temperature, JSON-first
        config_overrides = {
            'temperature_modifier': -0.2,  # Lower temperature for consistency
            'max_tokens': min(400, config['max_tokens']),  # Shorter for structured
            'format_hint': 'json_first',
            'structured_mode': True
        }

        estimated_tokens, estimated_time = self.lane_manager.estimate_resource_usage(
            Lane.STANDARD, input_complexity=0.8  # Structured is often simpler
        )

        return RouteResult(
            lane=Lane.STANDARD,
            intent_type=IntentType.STRUCTURED,
            confidence=intent_result.confidence,
            config_overrides=config_overrides,
            metadata={
                'routing_reason': 'structured_intent_detected',
                'intent_metadata': intent_result.metadata,
                **config
            },
            estimated_tokens=estimated_tokens,
            estimated_time=estimated_time
        )

    def _route_to_recall(self, intent_result: IntentResult, context: Dict) -> RouteResult:
        """Route to recall lane for memory queries"""
        config = self.lane_manager.get_lane_config(Lane.RECALL)

        # Recall optimization: minimal tokens, fast response
        config_overrides = {
            'temperature_modifier': -0.3,  # Very low temperature for factual recall
            'prefer_memory': True,
            'skip_reasoning': True
        }

        estimated_tokens, estimated_time = self.lane_manager.estimate_resource_usage(
            Lane.RECALL, input_complexity=0.3  # Recall is typically simple
        )

        return RouteResult(
            lane=Lane.RECALL,
            intent_type=intent_result.intent_type,
            confidence=intent_result.confidence,
            config_overrides=config_overrides,
            metadata={
                'routing_reason': 'recall_intent_detected',
                'intent_metadata': intent_result.metadata,
                'short_circuit_candidate': True,
                **config
            },
            estimated_tokens=estimated_tokens,
            estimated_time=estimated_time
        )

    def _route_to_deliberate(self, intent_result: IntentResult, context: Dict) -> RouteResult:
        """Route to deliberate lane for reasoning tasks"""
        config = self.lane_manager.get_lane_config(Lane.DELIBERATE)

        # Deliberate optimization: more tokens, higher temperature
        config_overrides = {
            'temperature_modifier': 0.1,  # Slightly higher for creativity
            'reasoning_mode': True,
            'allow_long_response': True
        }

        estimated_tokens, estimated_time = self.lane_manager.estimate_resource_usage(
            Lane.DELIBERATE, input_complexity=1.3  # Reasoning is more complex
        )

        return RouteResult(
            lane=Lane.DELIBERATE,
            intent_type=IntentType.REASONING,
            confidence=intent_result.confidence,
            config_overrides=config_overrides,
            metadata={
                'routing_reason': 'reasoning_intent_detected',
                'intent_metadata': intent_result.metadata,
                **config
            },
            estimated_tokens=estimated_tokens,
            estimated_time=estimated_time
        )

    def _route_to_tool_use(self, intent_result: IntentResult, context: Dict) -> RouteResult:
        """Route to tool use lane"""
        config = self.lane_manager.get_lane_config(Lane.TOOL_USE)

        config_overrides = {
            'enable_tools': True,
            'tool_coordination': True,
            'prefer_tools': True
        }

        estimated_tokens, estimated_time = self.lane_manager.estimate_resource_usage(
            Lane.TOOL_USE, input_complexity=1.1
        )

        return RouteResult(
            lane=Lane.TOOL_USE,
            intent_type=IntentType.TOOL_USE,
            confidence=intent_result.confidence,
            config_overrides=config_overrides,
            metadata={
                'routing_reason': 'tool_use_intent_detected',
                'intent_metadata': intent_result.metadata,
                **config
            },
            estimated_tokens=estimated_tokens,
            estimated_time=estimated_time
        )

    def _route_to_standard(self, user_input: str, context: Dict) -> RouteResult:
        """Default routing to standard lane"""
        config = self.lane_manager.get_lane_config(Lane.STANDARD)

        config_overrides = {
            'general_mode': True
        }

        estimated_tokens, estimated_time = self.lane_manager.estimate_resource_usage(
            Lane.STANDARD, input_complexity=1.0
        )

        return RouteResult(
            lane=Lane.STANDARD,
            intent_type=IntentType.GENERAL,
            confidence=0.5,  # Default confidence
            config_overrides=config_overrides,
            metadata={
                'routing_reason': 'default_standard_lane',
                **config
            },
            estimated_tokens=estimated_tokens,
            estimated_time=estimated_time
        )

    def _should_route_recall(self, user_input: str, ctx: Dict[str, Any]) -> bool:
        """Gate recall by verifying memory presence/relevance using scorer and history hints."""
        try:
            if not ctx or not ctx.get('history_available'):
                return False
            text = (user_input or '').lower()
            # Quick positive: last list count and a clear 'how many' reference
            if ctx.get('last_list_count') and 'how many' in text:
                return True
            # Score session summary relevance
            if self.scorer:
                summary = ctx.get('session_summary') or ''
                if summary:
                    s = self.scorer.score_context_quality(summary, 'recall', user_input)
                    if s and getattr(s, 'final_score', 0.0) >= float(getattr(self.config.routing, 'summary_gate_min_score', 0.5)) * 100:
                        return True
                # Fallback: score textual history snippet
                hist_text = ctx.get('history') or ''
                if hist_text:
                    h = self.scorer.score_context_quality(hist_text, 'recall', user_input)
                    if h and getattr(h, 'final_score', 0.0) >= float(getattr(self.config.routing, 'memory_gate_min_score', 0.6)) * 100:
                        return True
        except Exception:
            return False
        return False

    def log_routing_decision(self, route_result: RouteResult, user_input: str):
        """Log routing decision for monitoring and optimization"""
        logger.info(f"Routing decision: {route_result.lane.value} lane, "
                   f"intent: {getattr(route_result.intent_type, 'value', str(route_result.intent_type))}, "
                   f"confidence: {route_result.confidence:.2f}, "
                   f"estimated_time: {route_result.estimated_time:.1f}s")
